import React, { useState, useEffect } from 'react';
import {
  Box, Typography, Container, Grid, Card, CardContent, Avatar, IconButton, Menu, MenuItem,
  Button, Chip, List, ListItem, ListItemText, ListItemIcon, Divider, TextField,
  Paper, Stack, Tabs, Tab, Badge, InputAdornment, Fab, Dialog, DialogTitle,
  DialogContent, DialogActions, Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, Switch, FormControlLabel, Drawer, AppBar, Toolbar
} from '@mui/material';
import {
  AccountCircle, ExitToApp, Email, Chat, WhatsApp, Notifications, Send,
  Inbox, Drafts, Sent, Star, Archive, Delete, Search, Add, Attach,
  VideoCall, Phone, MoreVert, Settings, Refresh, Reply, Forward,
  People, Group, Business, Analytics, Schedule, AttachFile, EmojiEmotions
} from '@mui/icons-material';

function WebmailDashboard() {
  const [activeTab, setActiveTab] = useState(0);
  const [selectedEmail, setSelectedEmail] = useState(null);
  const [composeOpen, setComposeOpen] = useState(false);
  const [chatDrawerOpen, setChatDrawerOpen] = useState(false);
  const [stats, setStats] = useState({});
  const [emails, setEmails] = useState([]);
  const [chatRooms, setChatRooms] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [anchorEl, setAnchorEl] = useState(null);

  const userData = JSON.parse(localStorage.getItem('user_data') || '{}');
  const token = localStorage.getItem('webmail_token');

  useEffect(() => {
    fetchCommunicationData();
    // Set up real-time updates
    const interval = setInterval(fetchCommunicationData, 30000);
    return () => clearInterval(interval);
  }, []);

  const fetchCommunicationData = async () => {
    try {
      // Fetch communication stats
      const statsResponse = await fetch('/api/v1/communication/dashboard/stats/demo', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (statsResponse.ok) {
        const statsData = await statsResponse.json();
        setStats(statsData.stats);
      }

      // Fetch emails
      const emailsResponse = await fetch(`/api/v1/communication/email/inbox/demo/${userData.email}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (emailsResponse.ok) {
        const emailsData = await emailsResponse.json();
        setEmails(emailsData.emails || []);
      }

      // Fetch chat rooms
      const chatResponse = await fetch('/api/v1/communication/chat/rooms/demo', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (chatResponse.ok) {
        const chatData = await chatResponse.json();
        setChatRooms(chatData.rooms || []);
      }

      // Fetch notifications
      const notifResponse = await fetch(`/api/v1/communication/notifications/demo/${userData.id}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (notifResponse.ok) {
        const notifData = await notifResponse.json();
        setNotifications(notifData.notifications || []);
      }
    } catch (error) {
      console.error('Failed to fetch communication data:', error);
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    window.location.href = '/';
  };

  const StatCard = ({ title, value, icon, color, onClick }) => (
    <Card sx={{ 
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      '&:hover': { transform: 'translateY(-2px)', boxShadow: 3 }
    }} onClick={onClick}>
      <CardContent sx={{ p: 2 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <Box>
            <Typography variant="h4" sx={{ fontWeight: 700, color }}>{value}</Typography>
            <Typography variant="body2" color="text.secondary">{title}</Typography>
          </Box>
          <Avatar sx={{ bgcolor: color, width: 48, height: 48 }}>{icon}</Avatar>
        </Box>
      </CardContent>
    </Card>
  );

  const EmailList = () => (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Typography variant="h6">Inbox</Typography>
        <Box>
          <IconButton onClick={() => setComposeOpen(true)}><Add /></IconButton>
          <IconButton onClick={fetchCommunicationData}><Refresh /></IconButton>
        </Box>
      </Box>
      <List>
        {emails.map((email) => (
          <ListItem 
            key={email.id} 
            button 
            onClick={() => setSelectedEmail(email)}
            sx={{ 
              border: 1, 
              borderColor: 'divider', 
              borderRadius: 1, 
              mb: 1,
              bgcolor: email.read_status ? 'background.paper' : 'action.hover'
            }}
          >
            <ListItemIcon>
              <Avatar sx={{ width: 32, height: 32 }}>
                {email.from_email?.charAt(0)?.toUpperCase()}
              </Avatar>
            </ListItemIcon>
            <ListItemText
              primary={
                <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                  <Typography variant="subtitle2" sx={{ fontWeight: email.read_status ? 400 : 600 }}>
                    {email.from_email}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {new Date(email.created_at).toLocaleDateString()}
                  </Typography>
                </Box>
              }
              secondary={
                <Box>
                  <Typography variant="body2" sx={{ fontWeight: email.read_status ? 400 : 500 }}>
                    {email.subject}
                  </Typography>
                  <Typography variant="caption" color="text.secondary" noWrap>
                    {email.text_content?.substring(0, 100)}...
                  </Typography>
                </Box>
              }
            />
          </ListItem>
        ))}
      </List>
    </Box>
  );

  const ChatPanel = () => (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Typography variant="h6">Team Chat</Typography>
        <IconButton><Add /></IconButton>
      </Box>
      <List>
        {chatRooms.map((room) => (
          <ListItem key={room.id} button>
            <ListItemIcon>
              <Avatar sx={{ bgcolor: 'primary.main' }}>
                {room.type === 'group' ? <Group /> : <People />}
              </Avatar>
            </ListItemIcon>
            <ListItemText
              primary={room.name}
              secondary={`${room.member_count} members • ${room.messages_today} messages today`}
            />
            <Badge badgeContent={room.unread_count} color="error" />
          </ListItem>
        ))}
      </List>
    </Box>
  );

  const WhatsAppPanel = () => (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Typography variant="h6">WhatsApp Business</Typography>
        <Button variant="contained" startIcon={<Send />} size="small">
          Send Message
        </Button>
      </Box>
      <Grid container spacing={2}>
        <Grid item xs={12} md={6}>
          <Card variant="outlined">
            <CardContent>
              <Typography variant="subtitle1" gutterBottom>Quick Stats</Typography>
              <Typography variant="h4" color="success.main">
                {stats.whatsapp?.messages_today || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Messages sent today
              </Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} md={6}>
          <Card variant="outlined">
            <CardContent>
              <Typography variant="subtitle1" gutterBottom>Templates</Typography>
              <Typography variant="h4" color="primary.main">5</Typography>
              <Typography variant="body2" color="text.secondary">
                Approved templates
              </Typography>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );

  const NotificationsPanel = () => (
    <Box>
      <Typography variant="h6" gutterBottom>Notifications</Typography>
      <List>
        {notifications.map((notification) => (
          <ListItem key={notification.id}>
            <ListItemIcon>
              <Notifications color={notification.priority === 'high' ? 'error' : 'primary'} />
            </ListItemIcon>
            <ListItemText
              primary={notification.title}
              secondary={
                <Box>
                  <Typography variant="body2">{notification.message}</Typography>
                  <Typography variant="caption" color="text.secondary">
                    {new Date(notification.created_at).toLocaleString()}
                  </Typography>
                </Box>
              }
            />
            {!notification.read_status && <Chip label="New" size="small" color="primary" />}
          </ListItem>
        ))}
      </List>
    </Box>
  );

  const ComposeDialog = () => (
    <Dialog open={composeOpen} onClose={() => setComposeOpen(false)} maxWidth="md" fullWidth>
      <DialogTitle>Compose Email</DialogTitle>
      <DialogContent>
        <TextField fullWidth label="To" margin="normal" />
        <TextField fullWidth label="Subject" margin="normal" />
        <TextField
          fullWidth
          label="Message"
          multiline
          rows={10}
          margin="normal"
        />
      </DialogContent>
      <DialogActions>
        <Button onClick={() => setComposeOpen(false)}>Cancel</Button>
        <Button variant="contained" startIcon={<Send />}>Send</Button>
      </DialogActions>
    </Dialog>
  );

  return (
    <Box sx={{ display: 'flex', height: '100vh', bgcolor: '#f5f5f5' }}>
      {/* Sidebar */}
      <Paper sx={{ width: 280, bgcolor: 'white', borderRadius: 0 }}>
        <Box sx={{ p: 3, borderBottom: 1, borderColor: 'divider' }}>
          <Typography variant="h5" sx={{ fontWeight: 700, color: 'primary.main', mb: 1 }}>
            SSGzone Communication
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            <Avatar sx={{ width: 32, height: 32, mr: 2 }}>
              {userData.full_name?.charAt(0)}
            </Avatar>
            <Box>
              <Typography variant="body2" sx={{ fontWeight: 600 }}>{userData.full_name}</Typography>
              <Typography variant="caption" color="text.secondary">{userData.email}</Typography>
            </Box>
            <IconButton 
              sx={{ ml: 'auto' }} 
              onClick={(e) => setAnchorEl(e.currentTarget)}
            >
              <MoreVert />
            </IconButton>
          </Box>
        </Box>

        <List sx={{ p: 2 }}>
          <ListItem button selected={activeTab === 0} onClick={() => setActiveTab(0)}>
            <ListItemIcon><Email /></ListItemIcon>
            <ListItemText primary="Email" />
            <Badge badgeContent={stats.email?.unread_emails} color="error" />
          </ListItem>
          <ListItem button selected={activeTab === 1} onClick={() => setActiveTab(1)}>
            <ListItemIcon><Chat /></ListItemIcon>
            <ListItemText primary="Team Chat" />
            <Badge badgeContent={stats.chat?.messages_today} color="primary" />
          </ListItem>
          <ListItem button selected={activeTab === 2} onClick={() => setActiveTab(2)}>
            <ListItemIcon><WhatsApp /></ListItemIcon>
            <ListItemText primary="WhatsApp" />
          </ListItem>
          <ListItem button selected={activeTab === 3} onClick={() => setActiveTab(3)}>
            <ListItemIcon><Notifications /></ListItemIcon>
            <ListItemText primary="Notifications" />
            <Badge badgeContent={stats.notifications?.unread_notifications} color="error" />
          </ListItem>
          <Divider sx={{ my: 1 }} />
          <ListItem button>
            <ListItemIcon><Analytics /></ListItemIcon>
            <ListItemText primary="Analytics" />
          </ListItem>
          <ListItem button>
            <ListItemIcon><Settings /></ListItemIcon>
            <ListItemText primary="Settings" />
          </ListItem>
        </List>

        <Box sx={{ position: 'absolute', bottom: 0, width: 280, p: 2 }}>
          <Button fullWidth startIcon={<ExitToApp />} onClick={handleLogout}>
            Sign Out
          </Button>
        </Box>
      </Paper>

      <Box sx={{ flexGrow: 1, p: 3, overflow: 'auto', height: '100vh' }}>
        {/* Stats Cards */}
        <Grid container spacing={3} sx={{ mb: 3 }}>
          <Grid item xs={6} md={3}>
            <StatCard 
              title="Unread Emails" 
              value={stats.email?.unread_emails || 0}
              icon={<Email />} 
              color="#1976d2"
              onClick={() => setActiveTab(0)}
            />
          </Grid>
          <Grid item xs={6} md={3}>
            <StatCard 
              title="Chat Messages" 
              value={stats.chat?.messages_today || 0}
              icon={<Chat />} 
              color="#2e7d32"
              onClick={() => setActiveTab(1)}
            />
          </Grid>
          <Grid item xs={6} md={3}>
            <StatCard 
              title="WhatsApp Today" 
              value={stats.whatsapp?.messages_today || 0}
              icon={<WhatsApp />} 
              color="#388e3c"
              onClick={() => setActiveTab(2)}
            />
          </Grid>
          <Grid item xs={6} md={3}>
            <StatCard 
              title="Notifications" 
              value={stats.notifications?.unread_notifications || 0}
              icon={<Notifications />} 
              color="#f57c00"
              onClick={() => setActiveTab(3)}
            />
          </Grid>
        </Grid>

        {/* Main Content Area */}
        <Paper sx={{ p: 3, height: 'calc(100vh - 200px)', overflow: 'auto' }}>
          {activeTab === 0 && <EmailList />}
          {activeTab === 1 && <ChatPanel />}
          {activeTab === 2 && <WhatsAppPanel />}
          {activeTab === 3 && <NotificationsPanel />}
        </Paper>
      </Box>

      {/* Floating Action Button */}
      <Fab 
        color="primary" 
        sx={{ position: 'fixed', bottom: 16, right: 16 }}
        onClick={() => setComposeOpen(true)}
      >
        <Add />
      </Fab>

      {/* Compose Dialog */}
      <ComposeDialog />

      {/* User Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={() => setAnchorEl(null)}
      >
        <MenuItem onClick={() => setAnchorEl(null)}>
          <ListItemIcon><Settings /></ListItemIcon>
          Settings
        </MenuItem>
        <MenuItem onClick={handleLogout}>
          <ListItemIcon><ExitToApp /></ListItemIcon>
          Sign Out
        </MenuItem>
      </Menu>
    </Box>
  );
}

export default WebmailDashboard;
